import { MakeLogicType, actions, afterMount, kea, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import api, { CountedPaginatedResponse } from 'lib/api'

import type { SuppressionEntry } from './types'

export type { SuppressionEntry }

export type PaginatedSuppressions = CountedPaginatedResponse<SuppressionEntry>

const EMPTY_SUPPRESSIONS: PaginatedSuppressions = { count: 0, next: null, previous: null, results: [] }

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface suppressionListLogicValues {
    addSuppression: SuppressionEntry | null
    addSuppressionLoading: boolean
    currentPage: number
    newIdentifier: string
    removeSuppression: string | null
    removeSuppressionLoading: boolean
    showAddModal: boolean
    suppressions: PaginatedSuppressions
    suppressionsLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface suppressionListLogicActions {
    addSuppression: (identifier: string) => string
    addSuppressionFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    addSuppressionSuccess: (
        addSuppression: SuppressionEntry,
        payload?: string
    ) => {
        addSuppression: SuppressionEntry
        payload?: string
    }
    loadNextPage: () => {
        value: true
    }
    loadNextPageFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadNextPageSuccess: (
        suppressions: PaginatedSuppressions,
        payload?: {
            value: true
        }
    ) => {
        suppressions: PaginatedSuppressions
        payload?: {
            value: true
        }
    }
    loadPreviousPage: () => {
        value: true
    }
    loadPreviousPageFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadPreviousPageSuccess: (
        suppressions: PaginatedSuppressions,
        payload?: {
            value: true
        }
    ) => {
        suppressions: PaginatedSuppressions
        payload?: {
            value: true
        }
    }
    loadSuppressions: () => any
    loadSuppressionsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadSuppressionsSuccess: (
        suppressions: PaginatedSuppressions,
        payload?: any
    ) => {
        suppressions: PaginatedSuppressions
        payload?: any
    }
    removeSuppression: (identifier: string) => string
    removeSuppressionFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    removeSuppressionSuccess: (
        removeSuppression: string,
        payload?: string
    ) => {
        removeSuppression: string
        payload?: string
    }
    setCurrentPage: (page: number) => {
        page: number
    }
    setNewIdentifier: (identifier: string) => {
        identifier: string
    }
    setShowAddModal: (show: boolean) => {
        show: boolean
    }
}

export type suppressionListLogicType = MakeLogicType<suppressionListLogicValues, suppressionListLogicActions>

export const suppressionListLogic = kea<suppressionListLogicType>([
    path(['products', 'workflows', 'frontend', 'Suppression', 'suppressionListLogic']),
    actions({
        setCurrentPage: (page: number) => ({ page }),
        loadNextPage: true,
        loadPreviousPage: true,
        setShowAddModal: (show: boolean) => ({ show }),
        setNewIdentifier: (identifier: string) => ({ identifier }),
    }),
    reducers({
        currentPage: [
            1,
            {
                setCurrentPage: (_, { page }) => page,
                loadSuppressionsSuccess: () => 1,
                loadNextPageSuccess: (state) => state + 1,
                loadPreviousPageSuccess: (state) => Math.max(1, state - 1),
            },
        ],
        showAddModal: [
            false,
            {
                setShowAddModal: (_, { show }) => show,
                addSuppressionSuccess: () => false,
            },
        ],
        newIdentifier: [
            '',
            {
                setNewIdentifier: (_, { identifier }) => identifier,
                addSuppressionSuccess: () => '',
                setShowAddModal: (state, { show }) => (show ? state : ''),
            },
        ],
    }),
    loaders(({ values, actions }) => ({
        suppressions: {
            __default: EMPTY_SUPPRESSIONS,
            loadSuppressions: async (): Promise<PaginatedSuppressions> => {
                try {
                    return await api.messaging.getSuppressions(1)
                } catch (e) {
                    lemonToast.error('Failed to load suppression list')
                    // Rethrow so kea-loaders emits loadSuppressionsFailure and the currentPage reducer
                    // (which only advances on *Success) stays put — otherwise a failed page fetch would
                    // still tick currentPage and skip pages permanently.
                    throw e
                }
            },
            loadNextPage: async (): Promise<PaginatedSuppressions> => {
                try {
                    return await api.messaging.getSuppressions(values.currentPage + 1)
                } catch (e) {
                    lemonToast.error('Failed to load next page')
                    throw e
                }
            },
            loadPreviousPage: async (): Promise<PaginatedSuppressions> => {
                try {
                    return await api.messaging.getSuppressions(Math.max(1, values.currentPage - 1))
                } catch (e) {
                    lemonToast.error('Failed to load previous page')
                    throw e
                }
            },
        },
        addSuppression: {
            __default: null as SuppressionEntry | null,
            addSuppression: async (identifier: string): Promise<SuppressionEntry> => {
                try {
                    const result = await api.messaging.addSuppression(identifier)
                    lemonToast.success(`${identifier} added to suppression list`)
                    actions.loadSuppressions()
                    return result
                } catch (e) {
                    lemonToast.error('Failed to add to suppression list')
                    throw e
                }
            },
        },
        removeSuppression: {
            __default: null as string | null,
            removeSuppression: async (identifier: string): Promise<string> => {
                try {
                    await api.messaging.removeSuppression(identifier)
                    lemonToast.success(`${identifier} removed from suppression list`)
                    actions.loadSuppressions()
                    return identifier
                } catch (e) {
                    lemonToast.error('Failed to remove from suppression list')
                    throw e
                }
            },
        },
    })),
    afterMount(({ actions }) => {
        actions.loadSuppressions()
    }),
])
